#include <stdio.h>
#include <stdlib.h>
#define MAXN 100005
int A[MAXN];
int compare(const void *a, const void *b) { return (*(int*)a - *(int*)b); }
int maxPerimeter(int *A, int l, int r) {
    int max = 0;
    for (int i = l; i <= r - 2; i++) {
        for (int j = i + 1; j <= r - 1; j++) {
            for (int k = j + 1; k <= r; k++) {
                if (A[i] + A[j] > A[k] && A[i] + A[k] > A[j] && A[j] + A[k] > A[i]) {
                    max = (max > A[i] + A[j] + A[k]) ? max : A[i] + A[j] + A[k];
                }
            }
        }
    }
    return max;
}
int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    while (Q--) {
        int type;
        scanf("%d", &type);
        if (type == 1) {
            int pos, val;
            scanf("%d %d", &pos, &val);
            A[pos - 1] = val;
        } else {
            int l, r;
            scanf("%d %d", &l, &r);
            printf("%d\n", maxPerimeter(A, l - 1, r));
        }
    }
    return 0;
}

